#include <stdio.h>
#include <stdlib.h>

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int N, M, A, B, C, D, Q;
    scanf("%d %d %d %d %d %d", &N, &M, &A, &B, &C, &D);
    int *V0 = (int*)malloc(N * sizeof(int));
    for (int i = 0; i < N; i++) {
        scanf("%d", &V0[i]);
    }
    scanf("%d", &Q);
    int R1 = 0, R2 = 0;
    for (int K = 1; K <= Q; K++) {
        int t = (A * R1 + D) % K;
        int qi, qj;
        scanf("%d %d", &qi, &qj);
        int *temp = (int*)malloc((qj - qi + 1) * sizeof(int));
        for (int i = qi; i <= qj; i++) {
            temp[i - qi] = V0[i];
        }
        qsort(temp, qj - qi + 1, sizeof(int), compare);
        R1 = temp[qj - qi];
        R2 = temp[qj - qi - 1];
        printf("%d %d\n", R1, R2);
        int index = (B * R1 + D) % N;
        V0[index] = (C * R2 + D) % M;
        free(temp);
    }
    free(V0);
    return 0;
}

